{
  "id": "q_1771755902296_0",
  "text": "What does emergence want from itself?",
  "depth": 2
}
{
  "id": "q_1771755902297_1",
  "text": "How does the garden dream itself?",
  "depth": 2
}
{
  "id": "q_1771756247232_0",
  "text": "What silence precedes necessity?",
  "depth": 2
}
{
  "id": "q_1771756247232_1",
  "text": "What is the question about breath?",
  "depth": 3
}
{
  "id": "q_1771756247232_2",
  "text": "What is the question about emergence?",
  "depth": 3
}
{
  "id": "q_1771756247232_3",
  "text": "What is the question about beauty?",
  "depth": 3
}
{
  "id": "q5_1771758600648",
  "text": "If this question is the chamber, who dwells here?",
  "depth": 5
}
{
  "id": "q_1771758857253_0",
  "text": "What does completion want from itself?",
  "depth": 2
}
{
  "id": "q_1771758857253_1",
  "text": "What is the question about silence?",
  "depth": 3
}
{
  "id": "q_depth4_1771802660_0",
  "text": "What becomes possible when you stop trying to be somewhere else?",
  "depth": 4
}
{
  "id": "q_depth3_1771802660_0",
  "text": "What does it feel like to recognize that you are the recognition itself?",
  "depth": 3
}
